INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('990be4a9473c56e7', 'FL', '["state","county","special_district"]', 'ballot_access', 'When is the 2026 qualifying period for state and county offices?', '["When do I file my qualifying papers?","What are the exact dates for state qualifying in 2026?","Filing deadline for state representative"]', 'The qualifying period for state, multi-county, county, and special district offices begins at Noon on Monday, June 8, 2026, and ends at Noon on Friday, June 12, 2026.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&Search_String=&URL=0000-0099/0099/Sections/0099.061.html', 'Florida Statutes § 99.061(3)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to state legislative, county, and district offices (excluding federal and judicial).', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('65ef10b28c2f93fb', 'FL', '["state","district","county"]', 'ballot_access', 'When is the deadline to submit candidate petition signatures for the 2026 election?', '["What is the cutoff for turning in petitions?","Last day to submit signatures to the supervisor of elections","2026 petition deadline"]', 'Signatures must be submitted to the Supervisor of Elections prior to Noon on the 28th day preceding the first day of the qualifying period, which is Monday, May 11, 2026.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&Search_String=&URL=0000-0099/0099/Sections/0099.095.html', 'Florida Statutes § 99.095(3)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates utilizing the petition method to qualify for the ballot.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('f2ec8e2d1b568fb0', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When do I have to file my Appointment of Campaign Treasurer (Form DS-DE 9)?', '["Do I need a treasurer before I announce?","When must the DS-DE 9 be filed?","Can I open a bank account before filing my treasurer form?"]', 'You must file Form DS-DE 9 (Appointment of Campaign Treasurer and Designation of Campaign Depository) before you accept any contributions, make any expenditures, or open your campaign bank account.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.021.html', 'Florida Statutes § 106.021(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('27005fb95762b5c3', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the Statement of Candidate (Form DS-DE 84) and when is it due?', '["When do I have to read chapter 106?","Deadline to submit the Statement of Candidate","Filing the DS-DE 84"]', 'The Statement of Candidate certifies that you have been provided access to, read, and understand Florida Statutes Chapter 106. It must be filed within 10 days after filing your Appointment of Campaign Treasurer.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.023.html', 'Florida Statutes § 106.023(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('946c1ba64c2a8b32', 'FL', '["state","county","municipal"]', 'ballot_access', 'What is the Florida Resign-to-Run law?', '["Do I have to quit my current office to run for another?","Holding two offices in Florida","Resign to run rules"]', 'Florida''s Resign-to-Run law prohibits an officer from qualifying as a candidate for another state, district, county, or municipal public office if the terms, or any part thereof, overlap with each other, requiring them to submit an irrevocable resignation.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.012.html', 'Florida Statutes § 99.012(3)', '2026-05-09', 'static', 'statute_citation', 'Applies to currently serving public officers seeking another office with overlapping terms.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('289282b05ddd86e7', 'FL', '["state","county","municipal"]', 'ballot_access', 'When is the deadline to submit a resignation under the Resign-to-Run law?', '["How many days before qualifying do I have to resign?","Resign to run timeline","Deadline to quit current office for 2026 cycle"]', 'The irrevocable resignation must be submitted in writing at least 10 days prior to the first day of qualifying for the office the candidate intends to seek.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.012.html', 'Florida Statutes § 99.012(3)(c)', '2026-05-09', 'static', 'statute_citation', 'Applies to current officeholders qualifying for a new office.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('cab0e5216e6bef8d', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 Florida Primary Election?', '["What date is the primary in August?","Florida primary election 2026","When do voters vote in the 2026 primary?"]', 'The 2026 Florida Primary Election will be held on Tuesday, August 18, 2026 (the Tuesday 11 weeks prior to the general election).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0100/Sections/0100.061.html', 'Florida Statutes § 100.061', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates on the primary ballot in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('fb00bacd5bf14e98', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 Florida General Election?', '["What is the date for the November election?","When is election day 2026?","General election date Florida"]', 'The 2026 Florida General Election will be held on Tuesday, November 3, 2026.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0100/Sections/0100.031.html', 'Florida Statutes § 100.031', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates on the general election ballot in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('cc1ea940fbffbcb5', 'FL', '["state","county","municipal","special_district"]', 'finance_ethics', 'Can I accept campaign contributions from a corporation or LLC in Florida?', '["Are corporate donations legal in FL?","Can a company write my campaign a check?","Business contributions to candidates"]', 'Yes. Unlike federal law, Florida law includes corporations and LLCs in the definition of a ''person'' capable of making political contributions, subject to standard contribution limits.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011(14)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for state and local offices (does NOT apply to federal candidates).', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('6147c5e17a3a3fa3', 'FL', '["state","county","municipal"]', 'finance_ethics', 'What is the maximum individual contribution limit for a state legislative candidate?', '["How much can one person give my state house campaign?","Maximum donation limits in Florida","What is the cap for checks to my campaign?"]', 'Under current Florida law, an individual or entity may contribute up to $3,000 per election to a candidate for statewide or state legislative office. (Primary and General elections count as separate elections).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.08.html', 'Florida Statutes § 106.08(1)(a)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to candidates for Governor, Cabinet, State Senate, and State House.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('f2671edfcaee304d', 'FL', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept cash donations?', '["Is there a limit on cash contributions?","Can someone hand me a $100 bill?","Cash handling rules for FL campaigns"]', 'A candidate may not accept a contribution in cash or by means of a cashier''s check in excess of $50 per election from any single person or entity.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.09.html', 'Florida Statutes § 106.09(1)(a)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates raising funds under Florida state law.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('7dc2da2af4c70cc4', 'FL', '["federal","state","county"]', 'voter_interaction', 'Can Independent (NPA) voters vote in the Republican primary?', '["Is Florida a closed primary state?","Can Democrats cross over to vote for me?","Do you have to be a Republican to vote in the GOP primary?"]', 'No. Florida is a closed primary state. Only voters registered as members of a specific political party may vote for that party''s candidates in a primary election, unless a Universal Primary Contest is triggered.', 'http://www.leg.state.fl.us/statutes/index.cfm?Mode=Constitution&Submenu=3&Tab=statutes#A6S05', 'Florida Constitution, Article VI, Section 5(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to all partisan primary elections in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('64b30e3ae9a7236c', 'FL', '["federal","state","county"]', 'ballot_access', 'Does a write-in candidate ''close'' a primary that would otherwise be open to all voters?', '["The write-in loophole","If only Republicans are running, do Democrats get to vote?","Universal Primary Contest write-in rules"]', 'Yes. While a ''Universal Primary Contest'' opens a primary to all voters if all candidates are from one party, the Florida Division of Elections and state courts maintain that a qualified write-in candidate counts as opposition, which keeps the primary closed.', 'http://www.leg.state.fl.us/statutes/index.cfm?Mode=Constitution&Submenu=3&Tab=statutes#A6S05', 'Florida Constitution, Article VI, Section 5(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to partisan primary races facing ''Universal Primary'' triggers.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('fd254cecca12edee', 'FL', '["federal","state","county"]', 'candidate_eligibility', 'How long must I be registered as a Republican before I can run as a Republican candidate?', '["Can I switch parties to run for office?","Party affiliation duration rule","Sore loser party switching rules"]', 'You must be a registered member of the political party for which you are seeking nomination for at least 365 days before the beginning of the qualifying period.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.021.html', 'Florida Statutes § 99.021(1)(b)2', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates seeking the nomination of a major political party.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('cecefa9b07594829', 'FL', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Florida State House or Senate?', '["How old do I have to be for State Rep?","Residency rules for legislature","Do I have to live in the district before running?"]', 'A candidate must be an elector and resident of the district from which elected at the time of election, at least 21 years of age, and must have been a resident of Florida for the two years prior to the election.', 'http://www.leg.state.fl.us/statutes/index.cfm?Mode=Constitution&Submenu=3&Tab=statutes#A3S15', 'Florida Constitution, Article III, Section 15(c)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for the Florida House of Representatives and Florida Senate.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('ee3a2537dd9f638a', 'FL', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor of Florida?', '["How old to run for Governor?","Residency duration for statewide office","Requirements for Governor"]', 'A candidate for Governor must be an elector, at least 30 years of age, and must have resided in the state of Florida for the preceding seven years.', 'http://www.leg.state.fl.us/statutes/index.cfm?Mode=Constitution&Submenu=3&Tab=statutes#A4S05', 'Florida Constitution, Article IV, Section 5(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for Governor, Lieutenant Governor, and Cabinet offices.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('c18d1e67b6006830', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How far away from a polling place must my campaign volunteers stay when holding signs?', '["What is the 150-foot rule?","Distance for electioneering at voting sites","Where can we set up campaign tents?"]', 'No person or group may solicit voters, hand out materials, or engage in electioneering within 150 feet of the entrance to any polling place, early voting site, or secure ballot intake station (drop box).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0102/Sections/0102.031.html', 'Florida Statutes § 102.031(4)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns, volunteers, and electioneers.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('009047411511d45b', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can I hand out bottled water or snacks to voters waiting in line?', '["Giving food to voters in line","Is it illegal to hand out water at polls?","Line warming rules in Florida"]', 'No. Under Florida law, soliciting voters includes the intent to influence or interact with voters by giving items like food or beverages within the 150-foot zone or to the line of voters extending beyond it.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0102/Sections/0102.031.html', 'Florida Statutes § 102.031(4)(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates, volunteers, and third-party groups.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('1e594e5a0a4d9523', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline for the 2026 General Election?', '["When do the voter registration books close for November?","Last day to register for the general election","Voter registration cutoff date"]', 'The voter registration books close 29 days before the election. For the 2026 General Election, the deadline is Monday, October 5, 2026.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0097/Sections/0097.055.html', 'Florida Statutes § 97.055(1)(a)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all unregistered eligible voters.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('7b99d948d04a4b57', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline for the 2026 Primary Election?', '["When do the books close for the August primary?","Last day to register to vote in the primary","Deadline to switch party registration for the primary"]', 'The deadline to register to vote or change party affiliation before the 2026 Primary Election is Monday, July 20, 2026 (29 days before the election).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0097/Sections/0097.055.html', 'Florida Statutes § 97.055(1)(a)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all voters seeking to vote in the August primary.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('75c8f9b7df489ccf', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline for a voter to request a Vote-by-Mail ballot for the general election?', '["Last day to ask for a mail ballot","Cutoff for VBM requests","When do supervisors stop mailing ballots?"]', 'A request for a vote-by-mail ballot to be mailed to a voter must be received by the Supervisor of Elections no later than 5:00 p.m. on the 12th day before the election (October 22, 2026, for the general election).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.62.html', 'Florida Statutes § 101.62(2)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all eligible vote-by-mail voters.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('5e7ac5cdb33c5cfc', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the rules for Vote-by-Mail drop boxes in Florida?', '["Can voters drop off ballots 24/7?","Where are drop boxes located?","Rules for secure ballot intake stations"]', 'Secure ballot intake stations (drop boxes) may only be placed at the Supervisor''s main office, permanent branch offices, or designated early voting sites. They may only be utilized during the county''s active early voting hours and must be continuously monitored in person by an employee.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.69.html', 'Florida Statutes § 101.69(2)', '2026-05-09', 'static', 'statute_citation', 'Applies to voters returning mail ballots.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('d1e89ffdb3d4feef', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'How long is the early voting period in Florida?', '["When does early voting start and end?","How many days of early voting do we get?","Mandatory early voting window"]', 'Early voting must begin on the 10th day before an election and end on the 3rd day before the election. Supervisors of Elections have the option to offer additional days, starting as early as the 15th day and ending as late as the 2nd day before the election.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.657.html', 'Florida Statutes § 101.657(1)(d)', '2026-05-09', 'static', 'statute_citation', 'Applies to all state and federal elections.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('458f6c1387f64517', 'FL', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are the fines for late reports?","Does the state charge me if my treasurer is late?","Late filing fees"]', 'The fine is generally $50 per day for the first 3 days late and $500 per day thereafter, up to a maximum of 25% of the total receipts or expenditures for that reporting period. (Fines immediately preceding an election are strictly $500 per day).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07(8)(b)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates filing finance reports.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('c42860b1d707f9c8', 'FL', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What must I do with my surplus campaign funds after I lose or withdraw?', '["How do I dispose of leftover campaign money?","Can I keep my surplus funds?","Closing the account after the election"]', 'A candidate must dispose of surplus funds within 90 days of withdrawing, becoming unopposed, elected, or eliminated. Permissible methods include pro-rata refunds to contributors, donations to a 501(c)(3) charity, transfers to a political party, or transferring funds to an officeholder account (if elected).', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.141.html', 'Florida Statutes § 106.141(4)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates terminating their campaigns.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('762967258e186b0f', 'FL', '["federal","state","county","municipal","special_district"]', 'ballot_access', 'How is the partisan filing fee calculated for a candidate?', '["How much is the filing fee?","Cost to run for office as a Republican","Qualifying fee calculation"]', 'For partisan candidates, the total qualifying fee is 6% of the annual salary of the office sought. This consists of a 3% filing fee, a 1% election assessment, and a 2% party assessment.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.092.html', 'Florida Statutes § 99.092(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all partisan candidates requiring a filing fee.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('7c4464e48dc9c8a8', 'FL', '["judicial","county","municipal","special_district"]', 'ballot_access', 'What is the filing fee for nonpartisan offices, like judicial candidates?', '["How much to run for judge?","Nonpartisan qualifying fee","Do nonpartisan candidates pay the 2% party fee?"]', 'For nonpartisan candidates, the total qualifying fee is 4% of the annual salary of the office sought (a 3% filing fee plus a 1% election assessment). There is no party assessment.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0105/Sections/0105.031.html', 'Florida Statutes § 105.031(3)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to judicial and other nonpartisan candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('ae10d77e4ad0a4b9', 'FL', '["special_district"]', 'ballot_access', 'What is the filing fee to run for a special district office?', '["Cost to run for water board","Special district qualifying fee","Is there a flat fee for special districts?"]', 'Candidates for special district offices must pay a flat qualifying fee of $25.00, unless they choose to qualify by the petition method.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.061.html', 'Florida Statutes § 99.061(3)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to special district candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('152b33eddbda091e', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Can I avoid paying the filing fee by collecting petition signatures?', '["Candidate petition process","How to get on the ballot without paying","Petition alternative to filing fees"]', 'Yes. A candidate may qualify for the ballot by obtaining petition signatures from at least 1% of the total number of registered voters in the geographical area represented by the office sought from the last general election.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.095.html', 'Florida Statutes § 99.095(2)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates utilizing the petition method.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('851e363e92030c0b', 'FL', '["special_district"]', 'ballot_access', 'How many petition signatures are required for a special district office?', '["Special district petition threshold","Signatures needed for special district","Do I need 1% for a local district?"]', 'A candidate for a special district office must obtain only 25 signatures of registered voters in the geographical area represented by the office sought.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.095.html', 'Florida Statutes § 99.095(2)(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to special district candidates using the petition method.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('62be40f5756ef677', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Do I have to pay to have my petition signatures verified?', '["Cost to verify signatures","Does the Supervisor of Elections charge for petitions?","Petition checking fees"]', 'Yes. Candidates must pay the Supervisor of Elections 10 cents for each signature checked, or the actual cost of checking the signatures, whichever is less, paid in advance from the campaign account.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.097.html', 'Florida Statutes § 99.097(4)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates using the petition method.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('04cb8376d838e86d', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'What if I cannot afford the signature verification fee?', '["Waiver for petition fees","Oath of Undue Burden","What if my campaign has no money for signature checks?"]', 'You can file an Oath of Undue Burden with the qualifying officer, which exempts you from paying the signature verification fee. However, if you later pay a qualifying fee or receive contributions, you must reimburse the state.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.097.html', 'Florida Statutes § 99.097(4)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates unable to pay petition verification fees.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('2db50831f58e52b8', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Can I submit some petitions and pay the rest of the qualifying fee in cash?', '["Combining petitions and filing fees","Can I pay half and petition half?","Partial petition submission"]', 'No. Under Florida law, you cannot combine the petition method and the qualifying fee method. You must either obtain the required number of signatures or pay the entire qualifying fee.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.095.html', 'Florida Statutes § 99.095', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('7ea0410fca4ab1e6', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the standard campaign finance reporting schedule outside of election season?', '["How often do I file finance reports?","Monthly reporting schedule","When are DS-DE 12 reports due?"]', 'Candidates must file reports on the 10th day following the end of each calendar month from the time the campaign treasurer is appointed until the active qualifying period begins.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all active campaign accounts.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('ff010c588fa3701d', 'FL', '["state","county","municipal"]', 'finance_ethics', 'How does the reporting schedule change as the election gets closer?', '["Weekly reporting deadlines","Do I have to file daily reports?","Election season reporting frequency"]', 'Following the last day of qualifying, state and county candidates shift to bi-weekly reports, then weekly reports. Statewide candidates must file daily reports during the final 10 days preceding an election.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07(1)(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to active candidates post-qualifying.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('ca811ba283d3ec6e', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay my personal mortgage or rent?', '["Using campaign funds for living expenses","Can my campaign pay my rent?","Personal use of campaign money"]', 'No. A candidate may not use campaign funds to defray normal living expenses, other than expenses for transportation, meals, and lodging directly related to campaigning.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.1405.html', 'Florida Statutes § 106.1405', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates holding campaign funds.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('60c8c3c2cc6f3564', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is an Officeholder Account and how is it different from a campaign account?', '["What can I use an officeholder account for?","Keeping money after I win","Officeholder vs campaign account"]', 'An officeholder account is established to pay for expenses related to elected duties (like constituent mailers or district travel) that are not covered by the government. It is funded by surplus campaign funds, not ongoing donations.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.141.html', 'Florida Statutes § 106.141(5)', '2026-05-09', 'static', 'statute_citation', 'Applies to successfully elected candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('6811f4867396df76', 'FL', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the maximum amount of surplus campaign funds I can transfer to an officeholder account?', '["Limits on officeholder transfers","How much money can I keep for my officeholder account?","Transfer caps post-election"]', 'Transfers to an officeholder account are capped by office: $50,000 for statewide offices; $10,000 for multi-county/State Senate; $5,000 for State House; and $2,500 for single-county or local offices.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.141.html', 'Florida Statutes § 106.141(5)(b)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to elected officeholders transferring surplus funds.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('315df0054b1d1b20', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What constitutes an ''Independent Expenditure'' in Florida?', '["What makes a PAC expenditure independent?","Definition of independent expenditure","Coordinated vs independent spending"]', 'An independent expenditure is an expenditure made by a person or PAC expressly advocating the election or defeat of a candidate, which is NOT coordinated with, controlled by, or made at the direction of the candidate or their agent.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011(12)', '2026-05-09', 'static', 'statute_citation', 'Applies to PACs, individuals, and groups making political expenditures.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('8da9031ae423ec39', 'FL', '["state","county","municipal"]', 'finance_ethics', 'What is an Electioneering Communications Organization (ECO)?', '["What does an ECO do?","How is an ECO different from a campaign?","Florida ECO rules"]', 'An ECO is a Florida-specific political entity whose activities are limited to making expenditures for ''electioneering communications''—advertisements that feature a candidate but do not explicitly use ''magic words'' like ''vote for'' or ''vote against.''', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011(9)', '2026-05-09', 'static', 'statute_citation', 'Applies to political operatives and organizations in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('b0e5760db739a064', 'FL', '["state","county","municipal"]', 'finance_ethics', 'How is an ECO different from a Political Committee (PAC)?', '["ECO vs PAC","Why use an ECO instead of a PAC?","Difference between PAC and ECO"]', 'A PAC makes independent expenditures that *expressly advocate* for or against a candidate, whereas an ECO is legally restricted to only funding electioneering communications that mention a candidate without express advocacy.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011', '2026-05-09', 'static', 'statute_citation', 'Applies to groups organizing political expenditures.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('76bddc4e7ff7c54b', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to use a bank located in Florida for my campaign account?', '["Can I use an out-of-state bank for my campaign?","Campaign depository location rules","Where can I open my campaign checking account?"]', 'Yes. A campaign depository must be a bank, savings and loan association, or credit union authorized to transact business in the State of Florida.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.021.html', 'Florida Statutes § 106.021(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates opening a campaign depository.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('d3546d4c4f202fcb', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I appoint more than one campaign treasurer?', '["Can I have a deputy treasurer?","Multiple treasurers for one campaign","Who can sign campaign checks?"]', 'A candidate may appoint only one primary campaign treasurer but may appoint up to 3 deputy campaign treasurers per county in which the candidate is running. All must file the DS-DE 9 form.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.021.html', 'Florida Statutes § 106.021(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates appointing financial officers.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('70effe66597cbc05', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I withdraw cash from my campaign account for miscellaneous expenses?', '["Petty cash rules for campaigns","Can I pull cash out of the campaign ATM?","Using cash for campaign supplies"]', 'Yes, you may withdraw a limited amount for a petty cash fund ($500 per calendar quarter until qualifying, then $100 per week), but petty cash cannot be used to pay for salaries, candidate time, or office space.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.12.html', 'Florida Statutes § 106.12(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to campaigns utilizing petty cash funds.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('ba7ac7c16c99f6af', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Can I use my nickname on the ballot?', '["How do I list a nickname on my application?","What are the rules for ballot names?","Can I use my professional title as a nickname?"]', 'Yes, you may use a bona fide nickname. You must provide an affidavit stating you are generally known by that nickname or have used it as part of your legal name, and it cannot be used to indicate a political slogan or professional title.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.061.html', 'Florida Statutes § 99.061(7)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates appearing on a Florida ballot.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('a79f1436cfa80e46', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use a credit card for campaign expenses?', '["Are campaign credit cards allowed?","Can I put Facebook ads on a credit card?","Using credit cards vs checks"]', 'Yes, but it must be a credit card obtained specifically from the campaign depository (bank) where your campaign account is held, and it must be issued in the name of the campaign.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.125.html', 'Florida Statutes § 106.125', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates making credit expenditures.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('1c6fe5e2d7c69b2f', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Does my Candidate Oath need to be notarized?', '["Notarizing the DS-DE forms","Who can swear in my candidate oath?","Do I need a notary for my filing paperwork?"]', 'Yes. The Candidate Oath form (which varies depending on if you are Partisan, Nonpartisan, or Judicial) must be notarized or administered by an officer authorized to administer oaths in Florida.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.021.html', 'Florida Statutes § 99.021(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates filing an oath of office.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('d197a49e77e1d66c', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'If I withdraw from the race, do I get my filing fee back?', '["Refund for qualifying fee","Can I get my money back if I quit?","Qualifying fee refunds"]', 'No. A candidate''s qualifying fee is not refundable if the candidate withdraws after the close of the qualifying period.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.092.html', 'Florida Statutes § 99.092(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates who have paid a filing fee.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('576656246c44d3f5', 'FL', '["state","county","municipal"]', 'finance_ethics', 'Are candidates required to file their finance reports electronically?', '["Electronic filing system (EFS)","Can I mail in my finance report?","Do I have to use the state portal to file?"]', 'Yes. Candidates filing with the Florida Division of Elections must file all campaign finance reports electronically using the state''s Electronic Filing System (EFS). Local candidates use their county''s specified system.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.0705.html', 'Florida Statutes § 106.0705(2)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates submitting campaign finance reports.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('9d7024ebf54d78a1', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay an Ethics Commission fine?', '["Paying fines with donor money","Are ethics penalties a campaign expense?","Using campaign accounts for late fees"]', 'No. Civil penalties levied by the Florida Elections Commission or the Florida Commission on Ethics must be paid from the candidate''s personal funds, not from campaign contributions.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.265.html', 'Florida Statutes § 106.265(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates assessed a fine for ethics violations.', 'batch_2026-05-10T00-44-12_florida_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('3e7f52ef05f123c0', 'FL', '["state"]', 'ballot_access', 'What is the exact 2026 filing fee to run for Governor of Florida?', '["How much does it cost to get on the ballot for Governor?","Filing fee for statewide office","Qualifying fee for Florida Governor"]', 'Based on the 6% partisan formula and the statutory Governor''s salary of $141,400, the projected qualifying fee for Governor in 2026 is $8,484.00.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.092.html', 'Florida Statutes § 99.092(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to partisan candidates for Governor of Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('1756d121b8609782', 'FL', '["federal"]', 'ballot_access', 'What is the filing fee for a U.S. Senator or U.S. Representative in Florida?', '["How much to run for Congress in FL?","Congressional filing fee amount","US House qualifying fee"]', 'Based on the 6% partisan formula and the current federal congressional salary of $174,000, the qualifying fee for a U.S. House or U.S. Senate candidate is $10,440.00.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.092.html', 'Florida Statutes § 99.092(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to partisan candidates for U.S. Congress in Florida.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('0e6369c85c085298', 'FL', '["state","district"]', 'ballot_access', 'What is the filing fee for the Florida State Senate or State House?', '["State legislator filing fee","How much does it cost to run for State Rep?","State legislative qualifying cost"]', 'Based on the 6% partisan formula and the state legislative salary of $29,697, the qualifying fee for a State Senator or State Representative is $1,781.82.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.092.html', 'Florida Statutes § 99.092(1)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to partisan candidates for the Florida Legislature.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('825f0f81473fa85b', 'FL', '["judicial"]', 'ballot_access', 'What is the nonpartisan filing fee for a Circuit Court Judge?', '["How much to run for circuit judge?","Judicial qualifying fee","Nonpartisan fee for judge"]', 'Based on the 4% nonpartisan formula and the current circuit judge salary of $182,060, the qualifying fee for a Circuit Court Judge candidate is $7,282.40.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0105/Sections/0105.031.html', 'Florida Statutes § 105.031(3)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to candidates for Circuit Court Judge.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('5a9ef730aed1033b', 'FL', '["federal","state","county"]', 'ballot_access', 'If I run as a No Party Affiliation (NPA) candidate, are my petition signature requirements lower?', '["Do independents need fewer signatures?","NPA petition threshold","Minor party signature requirements"]', 'No. Minor party and No Party Affiliation (NPA) candidates must still obtain petition signatures from 1% of the total number of registered voters in the geographical area, exactly the same threshold as major party candidates.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.095.html', 'Florida Statutes § 99.095(2)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to minor party and NPA candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('30800b6197b20582', 'FL', '["federal","state","county","municipal","special_district"]', 'ballot_access', 'What are the petition and filing fee requirements to run as a Write-In candidate?', '["Write-in candidate fees","Do write-ins have to get signatures?","How to qualify as a write in"]', 'A write-in candidate is entirely exempt from paying a filing fee, election assessment, or party assessment, and is NOT required to submit petition signatures. They only need to file the required oaths and financial disclosures during the qualifying period.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0099/Sections/0099.061.html', 'Florida Statutes § 99.061(4)(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to all write-in candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('3e3ed5e74cf18cae', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'candidate_eligibility', 'Can a person with a felony conviction vote or run for office in Florida in 2026?', '["Amendment 4 rules","Can felons vote if they haven''t paid fines?","Felony voting restoration Florida"]', 'Yes, but strictly conditional. Voting rights are restored only upon the completion of all terms of their sentence, which Florida courts have definitively ruled includes the full payment of all restitution, fines, fees, and costs resulting from the conviction.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0000-0099/0098/Sections/0098.0751.html', 'Florida Statutes § 98.0751(2)(a)', '2026-05-09', 'volatile', 'statute_citation', 'Applies to Florida residents with past felony convictions (excluding murder/felony sexual offenses).', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('39f0f0208ab26268', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the specific disclaimer text required on my political advertising?', '["What does my yard sign have to say on it?","Pol Adv disclaimer wording","Campaign sign disclosure rules"]', 'Partisan candidates must use: ''Political advertisement paid for and approved by (name of candidate), (party affiliation), for (office sought).'' Nonpartisan candidates must use: ''Political advertisement paid for and approved by (name of candidate), for (office sought).''', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.143.html', 'Florida Statutes § 106.143(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidate political advertising.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('5f7aa5df070c1de8', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to put a political disclaimer on small novelty items like bumper stickers or t-shirts?', '["Disclaimer on campaign shirts","Do pens need a paid for by tag?","Novelty item advertising rules"]', 'No. The political disclaimer requirement does not apply to campaign messages designed to be worn by a person (t-shirts, hats) or to novelty items having a retail value of $10 or less which support, but do not oppose, a candidate.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.143.html', 'Florida Statutes § 106.143(8)', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all campaigns purchasing promotional merchandise.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('d974b279424f4b88', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to include a disclaimer on SMS text messages sent to voters?', '["Text message campaign rules","Do campaign texts need a paid for by?","Disclaimer for mass texts"]', 'Yes. A text message broadcast MUST include the ''Paid for by [Candidate Name]'' disclaimer unless it consists of fewer than 200 characters or includes a link to a website that prominently displays the full disclaimer.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.143.html', 'Florida Statutes § 106.143(10)', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns utilizing SMS/Text outreach.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('fa0b64750fb61e89', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How are signatures on Vote-by-Mail ballots verified?', '["How do they check mail-in ballots?","Signature matching on mail ballots","VBM verification process"]', 'The Supervisor of Elections or the county canvassing board compares the signature on the Voter''s Certificate (the ballot envelope) with the signature in the voter''s registration record to determine if they match.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.68.html', 'Florida Statutes § 101.68(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all returned Vote-by-Mail ballots.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('b177f842029f945b', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'If a voter''s signature is rejected on a mail-in ballot, what is the deadline for them to ''cure'' it?', '["Cure deadline for mail ballots","How late can someone fix a rejected ballot?","Fixing a signature match error"]', 'The voter must complete a ''Vote-by-Mail Ballot Cure Affidavit'' and provide a copy of their identification to the Supervisor of Elections no later than 5:00 p.m. on the 2nd day after the election.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.68.html', 'Florida Statutes § 101.68(4)(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to voters with missing or mismatched VBM signatures.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('4bb1f1cd62914434', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the qualifications to be a poll watcher?', '["Who can I hire to be a poll watcher?","Rules for being a poll observer","Do poll watchers have to live in the county?"]', 'A poll watcher must be a qualified and registered elector of the county in which they serve as a watcher. Candidates themselves may NOT serve as poll watchers.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.131.html', 'Florida Statutes § 101.131(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to individuals seeking to monitor voting locations.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('4ed9752c6ad27555', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the deadline for a campaign to designate its poll watchers?', '["When do I have to submit my poll watcher list?","Designation deadline for observers","How far in advance do I register poll watchers?"]', 'A candidate must designate poll watchers in writing to the Supervisor of Elections before Noon of the second Tuesday preceding the election.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.131.html', 'Florida Statutes § 101.131(2)', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns submitting poll watcher designations.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('e05148818c653efe', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can a poll watcher challenge a voter''s eligibility by talking to the voter?', '["What can a poll watcher say?","Can observers question voters?","Poll watcher conduct rules"]', 'No. Poll watchers may not interact with voters. All questions or challenges regarding a voter''s eligibility must be directed exclusively to the clerk of the polling room.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.131.html', 'Florida Statutes § 101.131(4)', '2026-05-09', 'static', 'statute_citation', 'Applies to the conduct of all designated poll watchers.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('e11232735ab5ec43', 'FL', '["state"]', 'finance_ethics', 'Can a state legislator raise money during the legislative session?', '["What is the legislative blackout period?","Fundraising during session","Can I solicit donations while in Tallahassee?"]', 'No. A legislator or candidate for the legislature may not solicit or accept a contribution during a regular legislative session (the 60-day session), or during any special session.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.08.html', 'Florida Statutes § 106.08(2)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to sitting legislators and challengers for state legislative seats.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('8d0e261799719872', 'FL', '["state"]', 'finance_ethics', 'Does the legislative session fundraising blackout apply to the candidate''s own money?', '["Can I self-fund during session?","Are personal loans banned during blackout?","Contributing to my own campaign during session"]', 'No. The blackout prohibition does not apply to a candidate''s own contributions or personal loans to their own campaign.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.08.html', 'Florida Statutes § 106.08(2)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to state legislative candidates self-funding.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('8b3af19c0c4bcd52', 'FL', '["county","municipal"]', 'recall_rules', 'Can a county commissioner or mayor be recalled from office?', '["Recall elections for local officials","Can we remove a city council member?","Are local officials subject to recall?"]', 'Yes. Any member of the governing body of a municipality or charter county may be removed from office by the electors through a statutory recall election process.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0100/Sections/0100.361.html', 'Florida Statutes § 100.361(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to elected officials of municipalities and charter counties.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('5c61714bf84a2ba7', 'FL', '["county","municipal"]', 'recall_rules', 'What are the legal grounds required to recall a local official?', '["Why can a mayor be recalled?","Recall justification","Reasons for local recall"]', 'A recall petition must be based on one or more of the following grounds: malfeasance, misfeasance, neglect of duty, drunkenness, incompetence, permanent inability to perform official duties, or conviction of a felony involving moral turpitude.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0100/Sections/0100.361.html', 'Florida Statutes § 100.361(1)(b)', '2026-05-09', 'static', 'statute_citation', 'Applies to voters/groups initiating a recall of a municipal or charter county official.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('a7281db10ce14726', 'FL', '["state","county","municipal"]', 'finance_ethics', 'Do I have to itemize every single contribution, even if it''s only $1?', '["Itemization threshold for donors","Do I need the address of a $5 donor?","Reporting small donations"]', 'Yes. Florida law requires the campaign treasurer to report the full name and address of *each* person who has made one or more contributions, regardless of the amount. Unlike other states, Florida does not have a ''minimum threshold'' for donor anonymity.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07(4)(a)1', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns filing finance reports.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('c7896a1f47fe1223', 'FL', '["state","county","municipal"]', 'finance_ethics', 'At what dollar amount do I have to report a donor''s occupation?', '["When do I ask for an employer?","Occupation reporting threshold","Do I need job info for small donations?"]', 'If a contribution is over $100, the campaign must report the specific occupation of the contributor. If the contributor is a business, you must report the principal type of business.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07(4)(a)1', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns receiving contributions over $100.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('753a9ab2ae151901', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When must my campaign deposit a contribution check into the bank?', '["How long can I hold a check before depositing?","Deposit deadlines for campaigns","Check cashing rules"]', 'All funds received by the campaign treasurer must be deposited into the designated campaign depository prior to the end of the 5th business day following the receipt of the contribution.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.05.html', 'Florida Statutes § 106.05', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaign treasurers managing funds.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('15c717e8cfdb2c66', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are campaign signs allowed in the public right-of-way?', '["Can I put signs in the median?","Right-of-way signage rules","Can the city take down my signs?"]', 'State law strictly prohibits the placement of political signs on the right-of-way of any state highway. Local ordinances typically enforce similar bans on county/city right-of-ways, subjecting illegal signs to immediate removal.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0400-0499/0479/Sections/0479.11.html', 'Florida Statutes § 479.11(8)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates placing campaign signs.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('12b63f97626b7b3d', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When can election officials begin opening and processing Vote-by-Mail ballots?', '["When do they start counting mail ballots?","Canvassing VBM timeline","When is the mail ballot envelope opened?"]', 'A county canvassing board may begin opening and processing (but not releasing the results of) vote-by-mail ballots at 7:00 a.m. on the 15th day before the election, provided the required Logic and Accuracy tests have been completed.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0101/Sections/0101.68.html', 'Florida Statutes § 101.68(2)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to election canvassing operations.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('0aab3e6418bd0b79', 'FL', '["state","county","municipal"]', 'finance_ethics', 'If I am running unopposed, when is my final campaign report due?', '["Unopposed candidate reporting","Do I keep reporting if nobody runs against me?","Closing out an unopposed campaign"]', 'If you become unopposed after the qualifying period ends, you must dispose of all surplus funds and file a final report within 90 days of the date you became unopposed.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.141.html', 'Florida Statutes § 106.141(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates who face no opposition on the ballot.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('f48d4c1b06bfbfc8', 'FL', '["state"]', 'finance_ethics', 'Does Florida offer public campaign financing for candidates?', '["Can I get state matching funds?","Public financing for Governor","Election Campaign Financing Act"]', 'Yes, but only for statewide offices (Governor and Cabinet). Eligible candidates who agree to expenditure limits can receive a state match for individual contributions of $250 or less.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.33.html', 'Florida Statutes § 106.33', '2026-05-09', 'static', 'statute_citation', 'Applies to statewide candidates opting into public financing.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('69d01af552de14b5', 'FL', '["state","county","municipal","special_district"]', 'finance_ethics', 'Does the Sunshine Law apply to candidate communications?', '["Can candidates talk to each other in private?","Sunshine law for un-elected candidates","Campaigning with other candidates"]', 'The Sunshine Law applies primarily to incumbents and elected ''members-elect''. However, if two candidates for the same multi-member board discuss issues that may foreseeably come before the board, it could trigger Sunshine Law violations if one or both are elected.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0200-0299/0286/Sections/0286.011.html', 'Florida Statutes § 286.011', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for multi-member boards (e.g., City Council, School Board).', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('07c49110994b45eb', 'FL', '["state","county","municipal"]', 'finance_ethics', 'What is the difference between the Florida Elections Commission and the Florida Commission on Ethics?', '["Who handles campaign finance complaints?","Ethics vs Elections Commission","Where do I file financial disclosures?"]', 'The Florida Elections Commission (Chapter 106) enforces campaign finance, advertising, and election laws. The Florida Commission on Ethics (Chapter 112) enforces personal financial disclosures (Form 6) and conflicts of interest.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.25.html', 'Florida Statutes § 106.25', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates subject to state ethics and election oversight.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('53fd83f445b2177a', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If a PAC coordinates an advertisement with my campaign, how is it reported?', '["Coordinated campaign ads","What if a PAC works with me?","Anti-coordination rules"]', 'If an expenditure is coordinated with a candidate, it loses its ''independent'' status and becomes an ''in-kind'' contribution to the campaign, which is strictly subject to the $3,000 contribution limit.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011(12)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns interacting with PACs or ECOs.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('315ec20719f47094', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I determine the value of an ''in-kind'' contribution?', '["Valuing donated goods","How much is a donated billboard worth?","In-kind contribution value"]', 'An in-kind contribution must be assigned a fair market value at the time of the contribution, representing the cost it would take to purchase the item or service on the open market.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011(5)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns receiving non-monetary donations.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('32e90ced79a4e5af', 'FL', '["state","county","municipal"]', 'finance_ethics', 'How do I report payments to independent contractors vs campaign employees?', '["Reporting campaign staff pay","Do I itemize contractor expenses?","Consultant payment reporting"]', 'Payments to both must be reported as expenditures. If an independent contractor (like a media consultant) makes sub-expenditures on your behalf, those must be itemized to the ultimate vendor to avoid ''dark money'' shielding.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns hiring staff and consultants.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('36cdacbb42b01798', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Is the time I spend working on my own campaign considered an ''in-kind'' contribution?', '["Do I have to report my own volunteer time?","Candidate exempt rule","Is my labor a campaign contribution?"]', 'No. The statutory definition of a contribution explicitly excludes services provided without compensation by individuals volunteering a portion or all of their time, including the candidate themselves.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.011.html', 'Florida Statutes § 106.011(5)(c)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates and volunteers.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('67fcf9430c6ea93b', 'FL', '["state","county","municipal"]', 'finance_ethics', 'How must I dispose of physical assets (like computers) purchased with campaign funds?', '["Can I keep campaign computers?","Disposing of physical assets post-election","Selling campaign equipment"]', 'Physical assets must be sold at fair market value and the proceeds deposited into the campaign account for surplus distribution. They may also be donated to a 501(c)(3) charity if the value is less than $500.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.141.html', 'Florida Statutes § 106.141(6)', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns terminating accounts with physical property.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('5a4a90d0bfb5fffd', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What constitutes voter intimidation under Florida law?', '["Can supporters yell at voters?","Voter intimidation laws","Is it a crime to block the polling entrance?"]', 'It is a 3rd-degree felony to directly or indirectly use or threaten to use force, violence, or intimidation to compel or deter a person from voting, or to interfere with the free exercise of their right to vote.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0104/Sections/0104.0515.html', 'Florida Statutes § 104.0515', '2026-05-09', 'static', 'statute_citation', 'Applies to all individuals near polling locations.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('d66d8bb5fa96e611', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can I pay someone to vote for me?', '["Is buying votes illegal?","Bribery to vote","Offering money for a vote"]', 'No. Under Florida''s corrupt influence statute, it is a felony to give or promise anything of value to another intending to buy their vote or corruptly influence their casting of a ballot.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0104/Sections/0104.061.html', 'Florida Statutes § 104.061', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns and individuals.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('9d42418468809c1b', 'FL', '["federal","state","county"]', 'runoff_rules', 'Does Florida have a primary runoff election if no candidate gets 50%?', '["Primary runoff rules","What if a three-way primary is close?","Plurality wins in Florida"]', 'No. For federal, state, and county partisan offices, Florida does not hold primary runoffs. The candidate receiving the highest number of votes (a plurality) in the primary becomes the party''s nominee.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0100/Sections/0100.061.html', 'Florida Statutes § 100.061', '2026-05-09', 'static', 'statute_citation', 'Applies to partisan primary elections.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('5934c90651ce6c0d', 'FL', '["judicial","county","municipal","special_district"]', 'runoff_rules', 'How do nonpartisan runoffs work?', '["Do judges have runoffs?","Nonpartisan top-two rule","When do school board races go to November?"]', 'In nonpartisan races (like judicial or school board), if no candidate receives a majority (50% + 1) of the votes in the primary, the top two vote-getters advance to a runoff in the general election.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0105/Sections/0105.051.html', 'Florida Statutes § 105.051', '2026-05-09', 'static', 'statute_citation', 'Applies to nonpartisan races.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('2b946b0c659725c1', 'FL', '["state","county","municipal"]', 'finance_ethics', 'If I decide to run for a different office than originally filed, what do I do with the funds?', '["Changing office sought","Can I roll my funds to a new race?","Switching campaigns mid-stream"]', 'You must notify the filing officer, dispose of all funds from the original campaign account pro-rata or to charity, and open a completely new campaign depository and treasurer appointment for the new office.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.021.html', 'Florida Statutes § 106.021(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates altering their targeted office before election.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('64038d9e0b833261', 'FL', '["state","county","municipal"]', 'finance_ethics', 'What must I do if I receive an anonymous contribution?', '["Can I keep anonymous donations?","Reporting unnamed cash","Anonymous cash rules"]', 'A candidate may not accept an anonymous contribution. If received and the donor cannot be identified, the contribution must be reported as anonymous and should be disposed of, typically by donating it to an exempt 501(c)(3) charity.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.07.html', 'Florida Statutes § 106.07', '2026-05-09', 'static', 'statute_citation', 'Applies to campaigns receiving untraceable funds.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('1652531b39480700', 'FL', '["state","county","municipal"]', 'finance_ethics', 'Can I serve as my own campaign treasurer?', '["Self-appointed treasurer","Do I have to hire an accountant?","Can the candidate be the treasurer?"]', 'Yes. Florida law explicitly permits a candidate to appoint themselves as their own primary or deputy campaign treasurer.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.021.html', 'Florida Statutes § 106.021(1)(c)', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates filing Form DS-DE 9.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('a88a23cea17c0e13', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are there specific wording requirements for my campaign checks?', '["Campaign check rules","What has to be printed on campaign bank checks?","Depository check wording"]', 'Yes. Checks drawn on the campaign depository must contain the exact statement: ''Campaign Account of (Name of Candidate)'' printed prominently on them.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.11.html', 'Florida Statutes § 106.11(1)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaign bank accounts.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('89789a420babf475', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can a campaign use a debit card linked to the campaign depository?', '["Debit cards for campaigns","Using bank cards instead of checks","Campaign depository debit rules"]', 'Yes, a candidate may use a debit card to make campaign expenditures, provided the card is obtained from the campaign depository and issued in the name of the campaign.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.11.html', 'Florida Statutes § 106.11(2)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('7f0c8f3639980936', 'FL', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to state a disclaimer on telephone solicitations?', '["Robocall disclaimers","Rules for phone banking","Disclaimer for live phone calls"]', 'Yes. Any telephone call supporting or opposing a candidate must identify the persons or organizations sponsoring the call by stating ''Paid for by...'' or ''Paid for on behalf of...'' prior to concluding.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.147.html', 'Florida Statutes § 106.147(1)(a)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns conducting phone outreach.', 'batch_2026-05-10T00-44-12_florida_full_v1'),
  ('6fd5d390512fe843', 'FL', '["state","county","municipal"]', 'finance_ethics', 'How long must the campaign treasurer keep financial records after the election?', '["Record retention rules","How long do I save receipts?","Keeping finance reports post-election"]', 'The campaign treasurer must preserve all accounts, receipts, and records for a period of at least two (2) years following the date the candidate files their final campaign report.', 'http://www.leg.state.fl.us/statutes/index.cfm?App_mode=Display_Statute&URL=0100-0199/0106/Sections/0106.06.html', 'Florida Statutes § 106.06(3)', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaign treasurers and candidates.', 'batch_2026-05-10T00-44-12_florida_full_v1')
